---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div">

const { class: className, ...props } = Astro.props
---

<div
  data-slot="input-group"
  role="group"
  class={cn(
    "group/input-group border-input has-[[data-slot=input-group-control]:focus-visible]:border-ring has-[[data-slot=input-group-control]:focus-visible]:ring-ring/50 has-[[data-slot][aria-invalid=true]]:border-destructive has-[[data-slot][aria-invalid=true]]:ring-destructive/20 dark:bg-input/30 dark:has-[[data-slot][aria-invalid=true]]:ring-destructive/40 relative flex h-9 w-full min-w-0 items-center rounded-md border shadow-xs transition-[color,box-shadow] outline-none in-data-[slot=combobox-content]:focus-within:border-inherit in-data-[slot=combobox-content]:focus-within:ring-0 has-[[data-slot=input-group-control]:focus-visible]:ring-3 has-[[data-slot][aria-invalid=true]]:ring-3 has-[>[data-align=block-end]]:h-auto has-[>[data-align=block-end]]:flex-col has-[>[data-align=block-start]]:h-auto has-[>[data-align=block-start]]:flex-col has-[>textarea]:h-auto has-[>[data-align=inline-end]]:[&>[data-slot=input-group-control]]:pr-1.5 has-[>[data-align=inline-start]]:[&>[data-slot=input-group-control]]:pl-1.5 has-[>[data-align=block-end]]:[&>input]:pt-3 has-[>[data-align=block-start]]:[&>input]:pb-3",
    className
  )}
  {...props}
>
  <slot />
</div>

<script>
  if (!document.documentElement.dataset.inputGroupBound) {
    document.documentElement.dataset.inputGroupBound = "true"

    document.addEventListener("click", (event) => {
      const target = event.target

      if (!(target instanceof Element)) return

      const addon = target.closest('[data-slot="input-group-addon"]')
      if (!(addon instanceof HTMLElement)) return

      if (
        target.closest(
          "a, button, input, textarea, select, option, summary, [role='button']"
        )
      ) {
        return
      }

      const group = addon.closest('[data-slot="input-group"]')
      const control = group?.querySelector('[data-slot="input-group-control"]')

      if (control instanceof HTMLElement) {
        control.focus()
      }
    })
  }
</script>

---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const variants = cva(
  "text-muted-foreground flex h-auto cursor-text items-center justify-center gap-2 py-1.5 text-sm font-medium select-none group-data-[disabled=true]/input-group:opacity-50 [&>kbd]:rounded-[calc(var(--radius)-5px)] [&>svg:not([class*='size-'])]:size-4",
  {
    variants: {
      align: {
        "inline-start":
          "order-first pl-2 has-[>a]:-ml-1 has-[>button]:-ml-1 has-[>kbd]:ml-[-0.15rem]",
        "inline-end":
          "order-last pr-2 has-[>a]:-mr-1 has-[>button]:-mr-1 has-[>kbd]:mr-[-0.15rem]",
        "block-start":
          "order-first w-full justify-start px-2.5 pt-2 group-has-[>input]/input-group:pt-2 [.border-b]:pb-2",
        "block-end":
          "order-last w-full justify-start px-2.5 pb-2 group-has-[>input]/input-group:pb-2 [.border-t]:pt-2",
      },
    },
    defaultVariants: {
      align: "inline-start",
    },
  }
)

type Props = HTMLAttributes<"div"> & VariantProps<typeof variants>

const {
  class: className,
  align = "inline-start",
  ...props
} = Astro.props as Props
---

<div
  role="group"
  data-slot="input-group-addon"
  data-align={align}
  class={cn(variants({ align }), className)}
  {...props}
>
  <slot />
</div>

---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import { Button, type ButtonVariantProps } from "@/components/ui/button"

const variants = cva("flex items-center gap-2 text-sm shadow-none", {
  variants: {
    size: {
      xs: "h-6 gap-1 rounded-[calc(var(--radius)-5px)] px-1.5 [&>svg:not([class*='size-'])]:size-3.5",
      sm: "",
      "icon-xs":
        "size-6 rounded-[calc(var(--radius)-5px)] p-0 has-[>svg]:p-0",
      "icon-sm": "size-8 p-0 has-[>svg]:p-0",
    },
  },
  defaultVariants: {
    size: "xs",
  },
})

type Props = VariantProps<typeof variants> &
  HTMLAttributes<"button"> &
  HTMLAttributes<"a"> & {
    type?: "button" | "submit" | "reset"
    variant?: ButtonVariantProps["variant"]
  }

const {
  class: className,
  type = "button",
  variant = "ghost",
  size = "xs",
  ...props
} = Astro.props as Props

const isLink = "href" in Astro.props
---

<Button
  data-size={size}
  type={isLink ? undefined : type}
  variant={variant}
  size={size}
  class={cn(variants({ size }), className)}
  {...props}
>
  <slot />
</Button>

